using AmazonAthena.Standard;
using AmazonAthena.Standard.Http.Client.Proxy;

namespace ConsoleApp;

var client = new AmazonAthenaClient.Builder()
.HttpClientConfig(config => config
    .Proxy(new ProxyConfigurationBuilder("http://localhost")
            .Port(8080)
            .Tunnel(false)
            .Auth("user", "pass")
    )
)
.Build();

try
{
    ApiResponse<ExampleType> response = await client.ExampleController.GetExampleType(body);
